stat = 0x80; //free 打印测试信息 配置电源管理：启用 PWR 时钟，设置 VIO18 电压为 3.3V 初始化 WS2812B 控制接口 设置状态变量为 0x80 (空闲状态) 主循环 : while (1) { total_bytes = rgb_data_bytes; Delay_Ms(200); stat = 0x80; //free if (stat != 0xFF) { //RGB1W completed if (stat < 0x80) { //got status in interrupt if (stat == RGB1W_ERR_OK) printf("1-wire finished\r\n"); else printf("1-wire error %02x\r\n", stat); stat = 0x80; //free } if (stat == 0x80 && total_bytes && timer_to_run) { //RAM mode for 1~3072 bytes data stat = 0xFF; //wait if (t1 == 0) { t1 = 1; RGB_RAM = RGBpbuf; } else if (t1 == 1) { t1 = 2; RGB_RAM = RGBpbuf1; } else if (t1 == 2) { t1 = 0; RGB_RAM = RGBpbuf2; } RGB1W_SendRAM(total_bytes, RGB_RAM, 1); total_bytes = 0; } } if (PIOC->D8_SYS_CFG & RB_INT_REQ) { //query if disable interrupt stat = PIOC->D8_CTRL_RD; //auto remove interrupt request after reading }
} 每隔 200ms 执行一次 RGB 数据更新 循环使用三个不同的 RGB 缓冲区 (RGBpbuf → RGBpbuf1 → RGBpbuf2 → 重复) 使用 RGB1W_SendRAM 函数发送 RGB 数据到 LED 灯带 处理传输状态和可能的错误 检查 PIOC 中断状态

