// 允许动态调整采样率和音频频率
#define DEFAULT_SAMPLE_RATE 8000
#define DEFAULT_FREQUENCY 440.0f void generate_sine_wave(s16* buffer, uint32_t size, float frequency, uint32_t sample_rate)
{ for (int i = 0; i < size; i += 2) { float t = ((float)i) / ((float)sample_rate); buffer[i] = 1000.0f * sinf(frequency * TAU * t); buffer[i + 1] = buffer[i]; // 立体声复制左声道 }
}

