// 增加音量控制和不同波形生成
void generate_square_wave(s16* buffer, uint32_t size, float frequency, uint32_t sample_rate, float amplitude)
{ for (int i = 0; i < size; i += 2) { float t = ((float)i) / ((float)sample_rate); float sine_val = sinf(frequency * TAU * t); buffer[i] = (sine_val >= 0) ? amplitude : -amplitude; buffer[i + 1] = buffer[i]; }
} // 音量控制函数
void adjust_volume(s16* buffer, uint32_t size, float volume_gain)
{ for (int i = 0; i < size; i++) { buffer[i] = (s16)((float)buffer[i] * volume_gain); }
}

