2.4.1 重置动态地址分配 (I3C_RSTDAA) 功能 : 发送 RSTDAA (Reset Dynamic Address Assignment) CCC 命令，重置总线上所有设备的动态地址 uint32_t I3C_RSTDAA()
{ uint32_t res = 0; I3C_ControllerHandleCCC(0x06, 0, I3C_GENERATE_STOP); // 等待完成或错误标志 while ((I3C_GetFlagStatus(I3C_EVR_FCF) == RESET) && (I3C_GetFlagStatus(I3C_EVR_ERRF) == RESET)) {} // 处理完成和错误标志 if (I3C_GetFlagStatus(I3C_EVR_FCF)) I3C_ClearFlag(I3C_FLAG_FCF); if (I3C_GetFlagStatus(I3C_EVR_ERRF)) { I3C_ClearFlag(I3C_CEVR_CERRF); res = 1; } return res;
} CCC 命令 : 0x06 (RSTDAA) 处理流程 : 发送 CCC 命令并生成停止条件 等待命令完成或错误标志 清除标志并返回结果 2.4.2 进入动态地址分配 (I3C_ENTDAA) 功能 : 发送 ENTDAA (Enter Dynamic Address Assignment) CCC 命令，为总线上的设备分配动态地址 uint32_t I3C_ENTDAA(uint8_t tgt_daa) 执行流程 : 发送 ENTDAA 命令 : I3C_ControllerHandleCCC(0x07, 0, I3C_GENERATE_STOP); CCC 命令: 0x07 (ENTDAA) 处理设备响应 : do { if (I3C_GetFlagStatus(I3C_EVR_TXFNFF)) { // 读取设备的静态地址 for (uint32_t index = 0; index < 8; index++) { while (I3C_GetFlagStatus((I3C_EVR_RXFNEF)) == RESET) {} payload |= (uint64_t)((uint64_t)I3C_ReadByte() << (index * 8)); } // 发送动态地址 I3C_WriteByte(tgt_daa++); target_payload[tgt_cnt] = payload; tgt_cnt++; }
} while ((I3C_GetFlagStatus(I3C_EVR_FCF) == RESET) && (I3C_GetFlagStatus(I3C_EVR_ERRF) == RESET)); 读取设备的静态地址（8 个字节） 为每个设备分配动态地址 存储设备的静态地址信息 处理完成和错误 : if (I3C_GetFlagStatus(I3C_EVR_FCF)) I3C_ClearFlag(I3C_FLAG_FCF);
if (I3C_GetFlagStatus(I3C_EVR_ERRF)) { I3C_ClearFlag(I3C_CEVR_CERRF); res = 1; }

