/** * @brief QSPI初始化（间接模式，适配W25Q128，四线传输） * @param 无 * @retval 无 */
void QSPI_Init(void)
{ // 1. 禁用QSPI，等待空闲 QSPI_CR &= ~(1 << 0); // EN=0，禁用QSPI while((QSPI_SR & (1 << 5)) != 0); // 等待BUSY=0（空闲） // 2. 配置器件配置寄存器（DCR） QSPI_DCR &= ~(0x1F << 16); // 清空FSIZE QSPI_DCR |= (FLASH_SIZE << 16); // 配置FLASH容量 QSPI_DCR &= ~(0x07 << 8); // 清空CSHT，默认1个周期 QSPI_DCR &= ~(1 << 0); // CKMODE=0（模式0） // 3. 配置控制寄存器（CR） QSPI_CR &= ~(0xFF << 0); // 清空PRESCALER，SCK=HCLK/1 QSPI_CR |= (0x03 << 0); // PRESCALER=3，SCK=HCLK/4（HCLK=144MHz，SCK=36MHz） QSPI_CR &= ~(0x1F << 8); // 清空FTHRES，默认0字节阈值 QSPI_CR |= (0x02 << 8); // FTHRES=2，阈值3字节 QSPI_CR &= ~(1 << 6); // DFM=0，禁用双闪存模式 QSPI_CR &= ~(1 << 3); // TCEN=0，禁用超时计数器 QSPI_CR &= ~(1 << 2); // DMAEN=0，禁用DMA QSPI_CR |= (1 << 17); // TCIE=1，使能传输完成中断 // 4. 配置通信配置寄存器（CCR） QSPI_CCR &= ~(1 << 28); // SIOO=0，每次命令都发送指令 QSPI_CCR &= ~(0x03 << 26); // 清空FMODE QSPI_CCR |= (0x01 << 26); // FMODE=01b（间接读取模式，可后续调整） QSPI_CCR &= ~(0x03 << 24); // 清空DMODE QSPI_CCR |= (0x03 << 24); // DMODE=11b（四线传输） QSPI_CCR &= ~(0x1F << 18); // 清空DCYC QSPI_CCR |= (0x0F << 18); // DCYC=15，15个SCK空周期 QSPI_CCR &= ~(0x03 << 14); // ABMODE=00b，无交替字节 QSPI_CCR &= ~(0x03 << 10); // 清空ADMODE QSPI_CCR |= (0x03 << 10); // ADMODE=11b（四线地址） QSPI_CCR &= ~(0x03 << 8); // 清空IMODE QSPI_CCR |= (0x01 << 8); // IMODE=01b（单线指令） QSPI_CCR &= ~(0xFF << 0); // 清空指令 QSPI_CCR |= FLASH_READ_CMD; // 初始指令为读指令 // 5. 配置数据长度（默认读取4字节） QSPI_DLR = 0x00000003; // 6. 使能QSPI QSPI_CR |= (1 << 0); // EN=1，使能QSPI while((QSPI_SR & (1 << 5)) != 0); // 等待BUSY=0，初始化完成
}

