/** * @brief QSPI间接读取数据 * @param addr：FLASH读取地址（24位） * @param buf：接收数据缓冲区 * @param len：读取字节数 * @retval 0：读取成功，1：读取失败 */
uint8_t QSPI_Read(uint32_t addr, uint8_t *buf, uint32_t len)
{ if(len == 0 || buf == NULL) return 1; // 1. 等待QSPI空闲 while((QSPI_SR & (1 << 5)) != 0); // 2. 配置读取参数 QSPI_CCR &= ~(0x03 << 26); // FMODE=01b（间接读取） QSPI_CCR &= ~(0xFF << 0); // 清空指令 QSPI_CCR |= FLASH_READ_CMD; // 读指令 QSPI_DLR = len - 1; // 配置读取长度 QSPI_AR = addr; // 配置读取地址 // 3. 启动读取命令 QSPI_CR |= (1 << 5); // START=1，启动命令 while((QSPI_SR & (1 << 5)) != 0); // 等待BUSY=0 while((QSPI_SR & (1 << 1)) == 0); // 等待TCF=1（传输完成） // 4. 读取数据 for(uint32_t i=0; i<len; i++) { buf[i] = QSPI_DR & 0xFF; // 逐字节读取 } // 5. 清零传输完成标志 QSPI_FCR |= (1 << 1); // CTCF=1，清零TCF return 0;
}

368.body:
/** * @brief QSPI间接写入数据（需先擦除对应扇区） * @param addr：FLASH写入地址（24位） * @param buf：待写入数据缓冲区 * @param len：写入字节数（不超过FLASH一页大小，通常256字节） * @retval 0：写入成功，1：写入失败 */
uint8_t QSPI_Write(uint32_t addr, uint8_t *buf, uint32_t len)
{ if(len == 0 || buf == NULL) return 1; // 1. 写使能 QSPI_CCR &= ~(0x03 << 26); // FMODE=00b（间接写入） QSPI_CCR &= ~(0xFF << 0); // 清空指令 QSPI_CCR |= FLASH_WRITE_EN; // 写使能指令 QSPI_DLR = 0x00000000; // 无数据传输 QSPI_CR |= (1 << 5); // 启动命令 while((QSPI_SR & (1 << 5)) != 0); // 等待BUSY=0 QSPI_FCR |= (1 << 1); // 清零TCF标志 // 2. 配置写入参数 QSPI_CCR &= ~(0xFF << 0); // 清空指令 QSPI_CCR |= FLASH_WRITE_CMD; // 页写指令 QSPI_DLR = len - 1; // 配置写入长度 QSPI_AR = addr; // 配置写入地址 // 3. 启动写入命令 QSPI_CR |= (1 << 5); // START=1，启动命令 while((QSPI_SR & (1 << 5)) != 0); // 等待BUSY=0 // 4. 写入数据 for(uint32_t i=0; i<len; i++) { QSPI_DR = buf[i]; // 逐字节写入 while((QSPI_SR & (0x3F << 8)) == 0x3F << 8); // 等待FIFO不满 } // 5. 等待写入完成 while((QSPI_SR & (1 << 1)) == 0); // 等待TCF=1 QSPI_FCR |= (1 << 1); // 清零TCF标志 return 0;
}

