/** * @brief QSPI状态轮询，监控FLASH擦除完成 * @param 无 * @retval 0：擦除完成，1：超时失败 */
uint8_t QSPI_Poll_Erase_Complete(void)
{ // 1. 配置状态轮询参数 QSPI_CCR &= ~(0x03 << 26); // FMODE=10b（状态轮询模式） QSPI_CCR &= ~(0xFF << 0); // 清空指令 QSPI_CCR |= FLASH_STATUS_CMD; // 状态读取指令 QSPI_DLR = 0x00000000; // 读取1字节状态 QSPI_PSMKR = 0x00000001; // 屏蔽其他位，监控bit0（BUSY位） QSPI_PSMAR = 0x00000000; // 匹配bit0=0（擦除完成） QSPI_CR &= ~(1 << 23); // PMM=0（AND模式） QSPI_CR |= (1 << 22); // APMS=1（匹配后自动停止） QSPI_CR |= (1 << 18); // SMIE=1（使能状态匹配中断） QSPI_PIR = 0x00FF; // 轮询间隔255个SCK周期 // 2. 启动轮询 QSPI_CR |= (1 << 5); // START=1，启动轮询 uint32_t timeout = 0xFFFFF; // 超时计数 while((QSPI_SR & (1 << 3)) == 0) // 等待SMF=1（状态匹配） { timeout--; if(timeout == 0) return 1; // 超时失败 } // 3. 清零状态匹配标志 QSPI_FCR |= (1 &lt;&lt; 3); // CSMF=1，清零SMF return 0;
}

