{ /* CAN寄存器复位 */ CAN_DeInit(CANx); CAN_StructInit(&CAN_InitStructure); /* CAN配置 */ CAN_InitStructure.CAN_TTCM = DISABLE; CAN_InitStructure.CAN_ABOM = ENABLE; CAN_InitStructure.CAN_AWUM = DISABLE; CAN_InitStructure.CAN_NART = DISABLE; CAN_InitStructure.CAN_RFLM = DISABLE; CAN_InitStructure.CAN_TXFP = DISABLE; CAN_InitStructure.CAN_Mode = CAN_Mode_Normal; CAN_InitStructure.CAN_SJW = CAN_SJW_1tq; CAN_InitStructure.CAN_BS1 = CAN_BS1_6tq; CAN_InitStructure.CAN_BS2 = CAN_BS2_8tq; CAN_InitStructure.CAN_Prescaler = 3; // 波特率1Mbps (72MHz / (3*(1+6+8))) = 1Mbps CAN_Init(CANx, &CAN_InitStructure); /* 过滤器配置 */ CAN_FilterInitStructure.CAN_FilterNumber = FilterNum; CAN_FilterInitStructure.CAN_FilterMode = CAN_FilterMode_IdMask; CAN_FilterInitStructure.CAN_FilterScale = CAN_FilterScale_32bit; CAN_FilterInitStructure.CAN_FilterIdHigh = 0x0000; CAN_FilterInitStructure.CAN_FilterIdLow = 0x0000; CAN_FilterInitStructure.CAN_FilterMaskIdHigh = 0x0000; CAN_FilterInitStructure.CAN_FilterMaskIdLow = 0x0000; CAN_FilterInitStructure.CAN_FilterFIFOAssignment = CAN_Filter_FIFO0; CAN_FilterInitStructure.CAN_FilterActivation = ENABLE; CAN_FilterInit(&CAN_FilterInitStructure); /* 配置中断 */ // ... CAN_ITConfig(CANx, CAN_IT_FMP0, ENABLE);
} 初始化CAN控制器，配置为正常模式 设置波特率为1Mbps（基于72MHz系统时钟） 配置CAN过滤器，使用32位ID掩码模式，接收所有CAN帧 启用CAN接收中断

