uint8_t CAN_Send_Msg(CAN_TypeDef *CANx, uint8_t *TxBuff, uint8_t Len)
{ uint8_t mbox; uint16_t i = 0; CanTxMsg TxMessage; TxMessage.StdId = 0x123; TxMessage.ExtId = 0x00; TxMessage.IDE = CAN_Id_Standard; TxMessage.RTR = CAN_RTR_Data; TxMessage.DLC = Len; for(i = 0; i < Len; i++) { TxMessage.Data[i] = TxBuff[i]; } mbox = CAN_Transmit(CANx, &TxMessage); i = 0; while((CAN_TransmitStatus(CANx, mbox) != CAN_TxStatus_Ok) && (i < 0xFFF)) { i++; } if(i == 0xFFF) { return 1; } else { return 0; }
} 发送CAN数据帧，使用标准ID 0x123 支持最多8字节数据发送 等待发送完成，超时时间约为4095个循环

