uint8_t CAN_Receive_Msg(CAN_TypeDef *CANx, uint8_t *RxBuff)
{ uint8_t i; CanRxMsg RxMessage; if(CAN_MessagePending(CANx, CAN_FIFO0) == 0) { return 0; } CAN_Receive(CANx, CAN_FIFO0, &RxMessage); for(i = 0; i < RxMessage.DLC; i++) { RxBuff[i] = RxMessage.Data[i]; } return RxMessage.DLC;
} 接收CAN数据帧 检查FIFO中是否有未处理的消息 将接收到的数据存储到指定的缓冲区 返回接收到的数据长度

