72.body:
EXTI核心寄存器（共6个），重点配置4个：中断使能、触发沿、软中断（可选）、中断标志清除，以EXTI0为例： void EXTI_Config(void)
{ // 1. 使能EXTI0中断（EXTI_INTENR寄存器，bit0对应EXTI0） R32_EXTI_INTENR |= (1 << 0); // 2. 配置上升沿触发（EXTI_RTENR寄存器，bit0对应EXTI0） R32_EXTI_RTENR |= (1 << 0); // 若需下降沿触发，配置EXTI_FTENR |= (1 << 0); 双边沿则两者都置1 // 3. 清除EXTI0中断标志（避免初始挂起） R32_EXTI_INTFR |= (1 << 0); // 写1清除标志
}

73.body:
EXTI0对应中断编号为6（参考datasheet向量表），属于共享中断，需分配内核、配置优先级、使能中断： void PFIC_Config(void)
{ // 1. 分配EXTI0（6号中断）给C0内核（PFIC_IALLOCR0，bit6对应6号中断） *(volatile uint32_t *)0x600 &= ~(1 << 6); // bit6清0=分配给C0 // 2. 配置6号中断优先级（PFIC_IPRIOR0，bit7~bit4对应6号中断） *(volatile uint32_t *)0x400 &= ~(0xF << 4); // 清0优先级位 *(volatile uint32_t *)0x400 |= (0x1 << 4); // 优先级1（次高） // 3. 使能6号中断（PFIC_IENR1，bit6对应6号中断） *(volatile uint32_t *)0x100 |= (1 << 6);
}

