uint16_t led_pins[] = {GPIO_Pin_1, GPIO_Pin_2, GPIO_Pin_10, GPIO_Pin_15}; void LED_Toggle(uint8_t led_index)
{ if(led_index >= 1 && led_index <= 4) { uint8_t idx = led_index - 1; LED_States[idx] = !LED_States[idx]; GPIO_WriteBit(led_ports[idx], led_pins[idx], LED_States[idx] ? Bit_RESET : Bit_SET); }
